CREATE PROCEDURE usp_PartitionedBulkArchive
    @ArchiveBeforeDate DATE,
    @BatchSize INT = 10000,
    @TargetDatabase NVARCHAR(128) = 'ArchiveDB'
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @RowsArchived BIGINT = 0;
    DECLARE @BatchRows INT = 1;
    DECLARE @DynSQL NVARCHAR(MAX);
    DECLARE @TableList TABLE (TableName NVARCHAR(128), PartitionColumn NVARCHAR(128));

    INSERT INTO @TableList VALUES
        ('Orders', 'OrderDate'),
        ('OrderItems', 'CreatedAt'),
        ('Shipments', 'ShipDate');

    DECLARE @Tbl NVARCHAR(128), @PartCol NVARCHAR(128);

    DECLARE tbl_cursor CURSOR FOR SELECT TableName, PartitionColumn FROM @TableList;
    OPEN tbl_cursor;
    FETCH NEXT FROM tbl_cursor INTO @Tbl, @PartCol;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @BatchRows = 1;
        WHILE @BatchRows > 0
        BEGIN
            SET @DynSQL = N'
            BEGIN TRANSACTION;
            INSERT INTO ' + QUOTENAME(@TargetDatabase) + '.dbo.' + QUOTENAME(@Tbl) + '
            SELECT TOP (' + CAST(@BatchSize AS NVARCHAR) + ') * FROM dbo.' + QUOTENAME(@Tbl) + '
            WHERE ' + QUOTENAME(@PartCol) + ' < @CutoffDate;
            SET @Affected = @@ROWCOUNT;
            DELETE FROM dbo.' + QUOTENAME(@Tbl) + '
            WHERE ' + QUOTENAME(@PartCol) + ' < @CutoffDate AND ' + QUOTENAME(@PartCol) + ' IN (
                SELECT TOP (' + CAST(@BatchSize AS NVARCHAR) + ') ' + QUOTENAME(@PartCol) + '
                FROM dbo.' + QUOTENAME(@Tbl) + ' WHERE ' + QUOTENAME(@PartCol) + ' < @CutoffDate
            );
            COMMIT TRANSACTION;';

            EXEC sp_executesql @DynSQL, N'@CutoffDate DATE, @Affected INT OUTPUT',
                @CutoffDate = @ArchiveBeforeDate, @Affected = @BatchRows OUTPUT;
            SET @RowsArchived += @BatchRows;
        END
        FETCH NEXT FROM tbl_cursor INTO @Tbl, @PartCol;
    END
    CLOSE tbl_cursor;
    DEALLOCATE tbl_cursor;

    SELECT @RowsArchived AS TotalRowsArchived;
END

CREATE OR REPLACE FUNCTION calculate_employee_bonus(
    p_employee_id IN NUMBER,
    p_performance_score IN NUMBER
) RETURN NUMBER IS
    v_base_salary    NUMBER;
    v_bonus_rate     NUMBER;
    v_bonus_amount   NUMBER;
BEGIN
    SELECT salary INTO v_base_salary
    FROM employees
    WHERE employee_id = p_employee_id;

    IF p_performance_score >= 90 THEN
        v_bonus_rate := 0.20;
    ELSIF p_performance_score >= 75 THEN
        v_bonus_rate := 0.15;
    ELSIF p_performance_score >= 60 THEN
        v_bonus_rate := 0.10;
    ELSE
        v_bonus_rate := 0.05;
    END IF;

    v_bonus_amount := v_base_salary * v_bonus_rate;
    RETURN v_bonus_amount;
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RETURN 0;
END calculate_employee_bonus;

