from pyspark.sql import SparkSession
from pyspark.sql.functions import col, when, udf
from pyspark.sql.types import DoubleType

spark = SparkSession.builder.appName('EmployeeBonusCalculation').getOrCreate()

# Vectorized approach using native Spark functions (preferred over UDF)
employees_df = spark.table('employees')

def apply_bonus_calculation(df, performance_score_col='performance_score'):
    bonus_rate = (
        when(col(performance_score_col) >= 90, 0.20)
        .when(col(performance_score_col) >= 75, 0.15)
        .when(col(performance_score_col) >= 60, 0.10)
        .otherwise(0.05)
    )
    return df.withColumn('bonus_rate', bonus_rate) \
             .withColumn('bonus_amount', col('salary') * bonus_rate)

result_df = apply_bonus_calculation(employees_df)
result_df.select('employee_id', 'salary', 'performance_score', 'bonus_rate', 'bonus_amount').show()

# UDF equivalent for scalar function usage
@udf(returnType=DoubleType())
def calculate_employee_bonus_udf(salary, performance_score):
    if salary is None:
        return 0.0
    if performance_score >= 90:
        bonus_rate = 0.20
    elif performance_score >= 75:
        bonus_rate = 0.15
    elif performance_score >= 60:
        bonus_rate = 0.10
    else:
        bonus_rate = 0.05
    return float(salary * bonus_rate)

udf_result = employees_df.withColumn(
    'bonus_amount',
    calculate_employee_bonus_udf(col('salary'), col('performance_score'))
)
udf_result.show()

